      {
        "selector": "[data-visual-regression='ignore-timestamp']",
        "reason": "System clock and last-updated indicators update dynamically on render."
      },
      {
        "selector": ".canvas-loading-spinner",
        "reason": "Asynchronous asset loading states may capture arbitrary frames of rotation."
      }
    ]
  },
